const queries = [
  // === TOPIC: Software Development ===
  { q: 'site:quora.com "software development company" OR "development agency" "recommend" OR "where can I find" OR "looking for" OR "how do I find"', platform: 'quora', topic: 'software_dev' },
  { q: 'site:quora.com "where to find" OR "best way to find" "software developers" OR "development team" OR "engineering team" "hire" OR "build"', platform: 'quora', topic: 'software_dev' },
  { q: 'site:quora.com "outsource" "software development" OR "AI development" OR "automation" OR "SaaS" "company" OR "agency" OR "team"', platform: 'quora', topic: 'software_dev' },

  // === TOPIC: Startups ===
  { q: 'site:quora.com "startup" "build" OR "develop" "software" OR "AI" OR "app" OR "platform" "agency" OR "company" OR "team" OR "hire"', platform: 'quora', topic: 'startups' },
  { q: 'site:quora.com "how do I build" OR "how to build" "AI" OR "SaaS" OR "automation" OR "software" "startup"', platform: 'quora', topic: 'startups' },
  { q: 'site:quora.com "need a developer" OR "need developers" OR "need a tech team" OR "looking for CTO" "startup" OR "idea" OR "product"', platform: 'quora', topic: 'startups' },

  // === TOPIC: SaaS ===
  { q: 'site:quora.com "build SaaS" OR "develop SaaS" OR "custom SaaS" "agency" OR "company" OR "team" OR "how"', platform: 'quora', topic: 'saas' },
  { q: 'site:quora.com "SaaS product" OR "SaaS platform" "build" OR "develop" OR "create" "where" OR "who" OR "best"', platform: 'quora', topic: 'saas' },

  // === BUYER INTENT: AI / ML ===
  { q: 'site:quora.com "AI development company" OR "AI agency" OR "machine learning company" "recommend" OR "best" OR "where" OR "how to find"', platform: 'quora', topic: 'ai_ml' },
  { q: 'site:quora.com "implement AI" OR "build AI" OR "integrate AI" OR "automate" "business" OR "company" OR "startup" "help" OR "agency" OR "developer"', platform: 'quora', topic: 'ai_ml' },
  { q: 'site:quora.com "computer vision" OR "machine learning" OR "LLM" OR "AI automation" "vendor" OR "agency" OR "company" OR "build" "recommend" OR "where"', platform: 'quora', topic: 'ai_ml' },

  // === BUYER INTENT: General Software / Agency Search ===
  { q: 'site:quora.com "hire software agency" OR "find software agency" OR "choose software company" "how" OR "best" OR "recommendation"', platform: 'quora', topic: 'agency_search' },
  { q: 'site:quora.com "custom software" "build" OR "develop" OR "create" "need" OR "looking" OR "want" "company" OR "agency" OR "developer"', platform: 'quora', topic: 'agency_search' },
  { q: 'site:quora.com "data pipeline" OR "data engineering" OR "data platform" "build" OR "need" OR "looking" "company" OR "agency" OR "team"', platform: 'quora', topic: 'agency_search' }
];
return queries.map(q => ({ json: q }));

const skipKeywords = [
  'how to become', 'how do i become', 'learn programming', 'learn to code',
  'best programming language', 'which language should i learn',
  'for hire', 'i am a developer', 'i offer', 'my services',
  'freelancer profile', 'available for work', 'hire me',
  'what is software development', 'definition of', 'history of',
  'quora partner', 'answer request'
];

const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const searchQ = data.search_parameters?.q || '';
  const organicResults = data.organic_results || [];

  // Infer topic from query
  let topic = 'general';
  if (searchQ.includes('startup')) topic = 'startups';
  else if (searchQ.includes('SaaS') || searchQ.includes('saas')) topic = 'saas';
  else if (searchQ.includes('AI') || searchQ.includes('machine learning') || searchQ.includes('automation')) topic = 'ai_ml';
  else if (searchQ.includes('software development')) topic = 'software_dev';
  else if (searchQ.includes('agency') || searchQ.includes('outsource')) topic = 'agency_search';

  for (const r of organicResults) {
    const link = r.link || '';
    if (!link) continue;
    if (!link.includes('quora.com')) continue;

    // Only include actual question pages, not topic/profile/space pages
    const isQuestion = link.includes('/What-') || link.includes('/How-') || link.includes('/Where-')
      || link.includes('/Why-') || link.includes('/Can-') || link.includes('/Is-')
      || link.includes('/Should-') || link.includes('/Which-') || link.includes('/Who-')
      || link.includes('/Does-') || link.includes('/Do-') || link.includes('/Are-')
      || (link.includes('quora.com/') && !link.includes('/profile/') && !link.includes('/topic/') && !link.includes('/spaces/'));
    if (!isQuestion) continue;

    const id = 'quora_' + link.replace(/[^a-z0-9]/gi, '').slice(-70);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (skipKeywords.some(kw => fullText.includes(kw))) continue;

    // Must have at least one buyer-intent signal
    const buyerSignals = [
      'where can i find', 'how do i find', 'looking for', 'recommend', 'best',
      'how to hire', 'who should i', 'outsource', 'need help', 'need a',
      'build', 'develop', 'create', 'automate', 'implement', 'integrate'
    ];
    if (!buyerSignals.some(s => fullText.includes(s))) continue;

    results.push({ json: {
      title,
      description: snippet,
      source: 'quora',
      source_url: link,
      source_id: id,
      posted_at: (() => { try { const d = r.date ? new Date(r.date) : null; return (d && !isNaN(d)) ? d.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: '',
      subreddit: topic,
      upvotes: 0,
      num_comments: 0,
      flair_text: topic,
      budget_text: '',
      platform: 'quora'
    }});
  }
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'quora' } }];
// Cap at 30 leads per run
return results.slice(0, 30);

const post = $input.item.json;
if (post._empty || post._noData) return { json: post };

const apiKey = $env.GOOGLE_AI_API_KEY;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, custom software, data pipelines.

These leads come from QUORA — people publicly asking questions about finding software/AI development companies, building products, or automating business processes. The person asking is often the BUYER themselves.

IDEAL LEAD: A founder, business owner, or decision-maker asking where to find a dev company, how to build AI/automation, or seeking recommendations for software agencies.

HARD EXCLUSIONS — Score overall_score 0.0 immediately, do not process:
- Lead is from India or an Indian company (location: India, .in domain, Indian city/company name context) → 0.0
- Lead is requesting to build a SaaS subscription product (we do NOT build SaaS products) → 0.0  
- Budget is clearly under $10,000 OR budget_score would be below 0.3 → 0.0
- Individual freelancer or [For Hire] ad → 0.0

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 1.0=explicitly asking for AI/ML/automation agency or dev company | 0.8=asking how to build AI/SaaS/automation product | 0.7=asking for software dev recommendation | 0.5=general tech question with business context | 0.2=learning/career question | 0.0=irrelevant
2. budget_score: 0.7=mentions enterprise/company context ($50K+ implied) | 0.6=mentions startup with funding | 0.5=unknown but business context | 0.4=small business implied | 0.2=individual/student | 0.0=no budget signal
3. urgency_score: 1.0=posted this week, actively deciding | 0.7=recent post, comparing options | 0.5=exploring options | 0.3=researching | 0.1=old question/academic
4. win_probability: 0.9=directly asking for agency/company referral | 0.7=asking how to find/hire, strong buyer signal | 0.5=asking about process, could be buyer | 0.3=ambiguous | 0.1=likely not a buyer

BUDGET ESTIMATION (ALWAYS fill estimated_budget_text, never null):
- Enterprise context → "$50K-$500K (enterprise implied)"
- Funded startup → "$25K-$150K (startup budget)"
- Business owner/SMB → "$10K-$75K (SMB scope)"
- Unknown context → "$10K-$50K (estimated from question context)"
- Individual/small → "$5K-$20K"

COMPANY EXTRACTION: Scan snippet for company name, person name, website. Most Quora posts won't have this — return null if not found. Never invent.`;

const prompt = SYSTEM_PROMPT + `\n\nScore this Quora question as a lead. Return ONLY a single valid JSON object:\n{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"summary":"2-4 sentence summary: what the person is asking, their apparent role/context, why they are or aren't a good lead for ScaleBuild AI","industry":"FinTech/HealthTech/SaaS/Manufacturing/eCommerce/General","tags":["tag1","tag2"],"reasoning":"Explain each score dimension — why this relevance (what makes them a buyer or not), why this budget score (what signals exist), why this urgency (how recent/active), why this win probability (how directly are they seeking a company). Give a clear recommendation: pursue or skip, and if pursue, what angle.","estimated_budget_text":"$X-$Y (reason)","tech_stack":[],"company_name":null,"lead_founder_name":null,"lead_website":null}\n\nQuora Question Title: ${post.title}\nTopic: ${post.subreddit}\nSnippet/Answers: ${(post.description||'').substring(0, 1200)}`;

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 100000, temperature: 0.2, responseMimeType: 'application/json' }
};

let s = null;
try {
  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
    body
  });
  const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
  const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) s = JSON.parse(match[0]);
} catch(e) {}

if (!s) s = {
  relevance_score:0.3, budget_score:0.4, urgency_score:0.3, win_probability:0.3,
  summary:'Parse error - using defaults', industry:'General', tags:[], reasoning:'Could not parse Gemini response',
  estimated_budget_text:'$10K-$50K (estimated)', tech_stack:[],
  company_name:null, lead_founder_name:null, lead_website:null
};

const overall = Math.round(((s.relevance_score*0.35)+(s.budget_score*0.30)+(s.urgency_score*0.15)+(s.win_probability*0.20))*100)/100;
const alert_tier = overall>=0.85?'instant':overall>=0.70?'digest':overall>=0.30?'dashboard':'discard';

return { json: {
  source_id: post.source_id, title: post.title, description: post.description,
  source: post.source, source_url: post.source_url, posted_at: post.posted_at,
  author: post.author||'', subreddit: post.subreddit||'quora',
  upvotes: 0, num_comments: 0, flair_text: post.flair_text||'Quora',
  relevance_score: s.relevance_score, budget_score: s.budget_score,
  urgency_score: s.urgency_score, win_probability: s.win_probability,
  overall_score: overall, ai_summary: s.summary, industry: s.industry,
  ai_tags: s.tags||[], ai_reasoning: s.reasoning,
  estimated_budget_text: s.estimated_budget_text||'',
  budget_mentioned: post.budget_text || s.estimated_budget_text || '',
  tech_stack: s.tech_stack||[], company_name: s.company_name||null,
  lead_founder: s.lead_founder_name||null, lead_company: s.company_name||null,
  lead_website: s.lead_website||null, lead_contact: null,
  lead_score: Math.round(overall*10),
  alert_tier, discovered_at: new Date().toISOString(), status:'new',
  location: s.location||null, deadline_text: null,
  outreach_draft: '',
  hunter_name:'', hunter_email:'', hunter_title:'', hunter_company:'',
  hunter_all_emails:'', hunter_all_names:'', hunter_all_titles:''
}};

const hunterResp = $input.item.json;
const original = $('Check - Has Lead Info').item.json;
const data = hunterResp?.data || {};
const emails = data.emails || [];
const org = data.organization || original.lead_company || '';

if (emails.length === 0) {
  return [{ json: { ...original, hunter_name: '', hunter_email: '', hunter_title: '', hunter_company: org, hunter_all_emails: '', hunter_all_names: '', hunter_all_titles: '' } }];
}

// Pick best contact by seniority priority
const priority = ['ceo','founder','co-founder','cto','owner','president','vp','director'];
const best = emails.find(e => priority.some(t => (e.position||'').toLowerCase().includes(t))) || emails[0];

const allEmails  = emails.map(e => e.value || '').filter(Boolean).join(', ');
const allNames   = emails.map(e => (e.first_name||e.last_name) ? `${e.first_name||''} ${e.last_name||''}`.trim() : '').filter(Boolean).join(', ');
const allTitles  = emails.map(e => e.position || '').filter(Boolean).join(', ');

return [{ json: {
  ...original,
  hunter_name:       best.first_name || best.last_name ? `${best.first_name||''} ${best.last_name||''}`.trim() : '',
  hunter_email:      best.value || '',
  hunter_title:      best.position || '',
  hunter_company:    org,
  hunter_all_emails: allEmails,
  hunter_all_names:  allNames,
  hunter_all_titles: allTitles
}}];

const seen = new Map();
for (const item of $input.all()) {
  const id = item.json.source_id;
  if (!id) continue;
  if (!seen.has(id)) {
    seen.set(id, item.json);
  } else {
    if (item.json.hunter_email && !seen.get(id).hunter_email) {
      seen.set(id, item.json);
    }
  }
}
return [...seen.values()]
  .sort((a, b) => (b.overall_score||0) - (a.overall_score||0))
  .map(json => ({ json }));
